Key;    public static List<OptionWithEndType> availableProps() {        ObjectTypeProperties propertiesStep = OneStepOfMultiSteps.getPreviousStepInstance(ObjectTypeProperties.class);        return propertiesStep.getColOpts();    }    @Override    protected void processPreSaved(IPluginContext pluginContext, Context currentCtx,                                   OneStepOfMultiSteps[] preSavedStepPlugins) {        if (StringUtils.isEmpty(this.pkField)) {            throw new IllegalStateException("pkField can not be empty");        }        if (StringUtils.isEmpty(this.titleKey)) {            throw new IllegalStateException("pkField can not be empty");        }        ObjectTypeProperties propertieSetStep = (ObjectTypeProperties) preSavedStepPlugins[Step2.getStepIndex()];        for (OntologyProperty prop : propertieSetStep.cols) {            if (StringUtils.equals(prop.name, pkField)) {                prop.setPk(true);            }        }    }    //    @SuppressWarnings("all")    //    public static List<ColumnMetaData> getOntologyObjTypeTargetTableCols() {    //        ObjectTypeProfile previousStepInstance = getPreviousStepInstance(ObjectTypeProfile.class);    //        return IPluginContext.getThreadLocalInstance().getContext().get(ObjectTypeProfile.class.getName());    //    }    @TISExtension    public static final class DftDesc extends BasicDesc {        public DftDesc() {            super();        }        @Override        public String getDisplayName() {            return "第三步";        }        @Override        public Step getStep() {            return Step.Step3;        }        @Override        public Optional<BasicDesc> nextPluginDesc(OneStepOfMultiSteps current) {            return Optional.empty();        }        @Override        public String getStepDescription() {            return "属性相关设置";        }    }}